\";i:5;s:10:\"image_path\";i:6;s:13:\"display_order\";i:7;s:9:\"is_active\";}s:10:\"\0*\0guarded\";a:1:{i:0;s:1:\"*\";}}}s:28:\"\0*\0escapeWhenCastingToString\";b:0;}s:9:\"homeCards\";O:39:\"Illuminate\\Database\\Eloquent\\Collection\":2:{s:8:\"\0*\0items\";a:1:{i:0;O:19:\"App\\Models\\HomeCard\":30:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:10:\"home_cards\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:16:{s:2:\"id\";i:1;s:5:\"title\";s:49:\"Soluções Inteligentes para Irrigação e Pivôs\";s:4:\"icon\";N;s:8:\"link_url\";N;s:11:\"description\";s:198:\"Automação e monitoramento remoto de sistemas de irrigação e pivôs centrais para otimizar o uso da água, reduzir custos com energia e maximizar a produtividade da lavoura de forma sustentável.\";s:14:\"detail_enabled\";i:1;s:12:\"detail_title\";s:49:\"Soluções Inteligentes para Irrigação e Pivôs\";s:15:\"detail_subtitle\";N;s:11:\"detail_body\";s:1000:\"Este serviço combina tecnologia IoT (Internet das Coisas), sensores de campo e softwares de gestão para transformar a irrigação agrícola em um processo de precisão. Através de uma plataforma centralizada, o produtor rural pode ligar, desligar e programar pivôs centrais à distância, além de monitorar a velocidade, direção e o volume de água aplicado.\n\nPrincipais recursos e benefícios:\n\nManejo de Precisão: Integração com sensores de umidade do solo e dados meteorológicos para aplicar a quantidade exata de água que a planta precisa, evitando desperdícios.\n\nEficiência Energética: Programação do funcionamento dos pivôs para horários com tarifas de energia mais baratas (horário reservado/noturno).\n\nAlertas em Tempo Real: Notificações instantâneas em caso de queda de pressão, desalinhamento do pivô, falta de energia ou furtos de cabos.\n\nRelatórios de Desempenho: Histórico completo de consumo de água e energia para auditorias e certificações sustentáveis.\";s:17:\"detail_image_path\";s:65:\"imagens/cards/whatsapp-image-2026-04-01-at-172322-trc0pm2hok.webp\";s:20:\"detail_image_caption\";s:4:\"logo\";s:18:\"detail_button_text\";s:8:\"ver mais\";s:13:\"display_order\";i:1;s:9:\"is_active\";i:1;s:10:\"created_at\";s:19:\"2026-05-07 22:15:27\";s:10:\"updated_at\";s:19:\"2026-05-28 20:12:01\";}s:11:\"\0*\0original\";a:16:{s:2:\"id\";i:1;s:5:\"title\";s:49:\"Soluções Inteligentes para Irrigação e Pivôs\";s:4:\"icon\";N;s:8:\"link_url\";N;s:11:\"description\";s:198:\"Automação e monitoramento remoto de sistemas de irrigação e pivôs centrais para otimizar o uso da água, reduzir custos com energia e maximizar a produtividade da lavoura de forma sustentável.\";s:14:\"detail_enabled\";i:1;s:12:\"detail_title\";s:49:\"Soluções Inteligentes para Irrigação e Pivôs\";s:15:\"detail_subtitle\";N;s:11:\"detail_body\";s:1000:\"Este serviço combina tecnologia IoT (Internet das Coisas), sensores de campo e softwares de gestão para transformar a irrigação agrícola em um processo de precisão. Através de uma plataforma centralizada, o produtor rural pode ligar, desligar e programar pivôs centrais à distância, além de monitorar a velocidade, direção e o volume de água aplicado.\n\nPrincipais recursos e benefícios:\n\nManejo de Precisão: Integração com sensores de umidade do solo e dados meteorológicos para aplicar a quantidade exata de água que a planta precisa, evitando desperdícios.\n\nEficiência Energética: Programação do funcionamento dos pivôs para horários com tarifas de energia mais baratas (horário reservado/noturno).\n\nAlertas em Tempo Real: Notificações instantâneas em caso de queda de pressão, desalinhamento do pivô, falta de energia ou furtos de cabos.\n\nRelatórios de Desempenho: Histórico completo de consumo de água e energia para auditorias e certificações sustentáveis.\";s:17:\"detail_image_path\";s:65:\"imagens/cards/whatsapp-image-2026-04-01-at-172322-trc0pm2hok.webp\";s:20:\"detail_image_caption\";s:4:\"logo\";s:18:\"detail_button_text\";s:8:\"ver mais\";s:13:\"display_order\";i:1;s:9:\"is_active\";i:1;s:10:\"created_at\";s:19:\"2026-05-07 22:15:27\";s:10:\"updated_at\";s:19:\"2026-05-28 20:12:01\";}s:10:\"\0*\0changes\";a:0:{}s:8:\"\0*\0casts\";a:2:{s:9:\"is_active\";s:7:\"boolean\";s:14:\"detail_enabled\";s:7:\"boolean\";}s:17:\"\0*\0classCastCache\";a:0:{}s:21:\"\0*\0attributeCastCache\";a:0:{}s:13:\"\0*\0dateFormat\";N;s:10:\"\0*\0appends\";a:0:{}s:19:\"\0*\0dispatchesEvents\";a:0:{}s:14:\"\0*\0observables\";a:0:{}s:12:\"\0*\0relations\";a:0:{}s:10:\"\0*\0touches\";a:0:{}s:10:\"timestamps\";b:1;s:13:\"usesUniqueIds\";b:0;s:9:\"\0*\0hidden\";a:0:{}s:10:\"\0*\0visible\";a:0:{}s:11:\"\0*\0fillable\";a:13:{i:0;s:5:\"title\";i:1;s:11:\"description\";i:2;s:14:\"detail_enabled\";i:3;s:12:\"detail_title\";i:4;s:15:\"detail_subtitle\";i:5;s:11:\"detail_body\";i:6;s:17:\"detail_image_path\";i:7;s:20:\"detail_image_caption\";i:8;s:18:\"detail_button_text\";i:9;s:4:\"icon\";i:10;s:8:\"link_url\";i:11;s:13:\"display_order\";i:12;s:9:\"is_active\";}s:10:\"\0*\0guarded\";a:1:{i:0;s:1:\"*\";}}}s:28:\"\0*\0escapeWhenCastingToString\";b:0;}s:7:\"gallery\";O:39:\"Illuminate\\Database\\Eloquent\\Collection\":2:{s:8:\"\0*\0items\";a:0:{}s:28:\"\0*\0escapeWhenCastingToString\";b:0;}}',1780000925),('site:v166:home','a:5:{s:8:\"settings\";a:10:{s:12:\"company_name\";s:21:\"Felestrino Soluções\";s:7:\"tagline\";s:64:\"Tecnologia para monitoramento hídrico e irrigação inteligente\";s:5:\"phone\";s:12:\"31 9843-2510\";s:6:\"phone2\";s:12:\"31 9843-2510\";s:7:\"message\";s:2:\"oi\";s:5:\"email\";s:33:\"contato@felestrinosolucoes.com.br\";s:7:\"address\";N;s:5:\"about\";N;s:9:\"seo_title\";s:60:\"Felestrino Soluções | Irrigação e Monitoramento Hídrico\";s:15:\"seo_description\";s:160:\"Soluções Inteligentes para Irrigação