INSERT INTO `home_cards` VALUES (1,'Soluções Inteligentes para Irrigação e Pivôs','irrigação',NULL,'Automação e monitoramento remoto de sistemas de irrigação e pivôs centrais para otimizar o uso da água, reduzir custos com energia e maximizar a produtividade da lavoura de forma sustentável.',1,'Soluções Inteligentes para Irrigação e Pivôs',NULL,'Este serviço combina tecnologia IoT (Internet das Coisas), sensores de campo e softwares de gestão para transformar a irrigação agrícola em um processo de precisão. Através de uma plataforma centralizada, o produtor rural pode ligar, desligar e programar pivôs centrais à distância, além de monitorar a velocidade, direção e o volume de água aplicado.\n\nPrincipais recursos e benefícios:\n\nManejo de Precisão: Integração com sensores de umidade do solo e dados meteorológicos para aplicar a quantidade exata de água que a planta precisa, evitando desperdícios.\n\nEficiência Energética: Programação do funcionamento dos pivôs para horários com tarifas de energia mais baratas (horário reservado/noturno).\n\nAlertas em Tempo Real: Notificações instantâneas em caso de queda de pressão, desalinhamento do pivô, falta de energia ou furtos de cabos.\n\nRelatórios de Desempenho: Histórico completo de consumo de água e energia para auditorias e certificações sustentáveis.','imagens/cards/5db3a-durante-a-expointer-deste-ano-a-empresa-demostrara-suas-novas-solucoes-inteligentes-de-gerenciamento-de-pivos-2-bylzvb7gnn.webp',NULL,'ver mais',1,1,'2026-05-08 01:15:27','2026-05-29 22:44:16'),(2,'Controle e Monitoramento de Sistemas de Água e Esgoto','monitoramento',NULL,'Gestão em tempo real e automação de redes de saneamento, estações de tratamento (ETA/ETE) e reservatórios, garantindo eficiência operacional e redução drástica de perdas de água.',1,'Controle e Monitoramento de Sistemas de Água e Esgoto',NULL,'Uma solução robusta voltada para concessionárias públicas, privadas e indústrias, focada na supervisão completa do ciclo da água e do esgoto. O sistema utiliza telemetria avançada para monitorar variáveis críticas em tempo real, permitindo uma gestão proativa que antecipa falhas e otimiza a distribuição.\n\nPrincipais recursos e benefícios:\n\nCombate a Perdas: Detecção automatizada de vazamentos ocultos e Rompimentos de adutoras através do balanço hidráulico e análise de pressão na rede.\n\nAutomação de Estações (ETA/ETE): Controle remoto de motobombas, inversores de frequência e monitoramento de parâmetros de qualidade da água (pH, turbidez, cloro).\n\nGestão de Reservatórios: Monitoramento contínuo de níveis para evitar transbordamentos ou desabastecimento da população.\n\nManutenção Preditiva: Identificação de anomalias no funcionamento de bombas e motores antes que ocorra uma quebra total, reduzindo custos de manutenção corretiva.','imagens/cards/2debfa-621b0a27e0c2418ba08c44414e7a520bmv2-nrrgglpf56.webp',NULL,NULL,2,1,'2026-05-28 23:12:31','2026-05-29 22:47:15'),(3,'Monitoramento de Chuvas e Níveis de Rios em Tempo Real','monitoramento',NULL,'Telemetria meteorológica e hidrológica avançada para a prevenção de desastres, gestão de bacias hidrográficas e suporte à tomada de decisões em Defesas Civis, usinas e agronegócio.',1,'Monitoramento de Chuvas e Níveis de Rios em Tempo Real',NULL,'Este serviço consiste na implantação de redes de estações teleométricas (pluviômetros e linígrafos) que coletam e transmitem dados ambientais continuamente. Focado na segurança e na previsibilidade, o sistema transforma dados brutos de chuva e nível de rios em inteligência para prever cheias, secas extremas e gerenciar recursos hídricos.\n\nPrincipais recursos e benefícios:\n\nAlertas de Emergência: Emissão automática de avisos (via SMS, e-mail ou sirenes) quando o nível do rio ou o volume de chuva atinge cotas de atenção, alerta ou transbordo.\n\nModelagem Hidrológica: Criação de históricos confiáveis para prever o comportamento de bacias hidrográficas e planejar o escoamento urbano ou industrial.\n\nOperação de Reservatórios e PCHs: Suporte essencial para usinas hidrelétricas no controle de vazão e na segurança de barragens.\n\nAcesso Remoto via Nuvem: Dashboards intuitivos com mapas de calor e gráficos de evolução das chuvas, acessíveis de qualquer dispositivo conectado à internet.','imagens/cards/gemini-generated-image-i9uxfmi9uxfmi9ux-piogh0klpz.webp',NULL,NULL,3,1,'2026-05-28 23:17:06','2026-05-29 22:47:18');
